mapper.select:
/* adm-role-rolebyusergroup-sql-oracle.xml - selectUserGroupCount */
SELECT COUNT(*)
  FROM TADMIN_MST_URGR


	      #{SEARCH_CONDITION}

/* adm-role-rolebyusergroup-sql-oracle.xml - selectUserGroup */
#{GRIDPAGING_ROWNUMTYPE_TOP}
				SELECT URGRKEY
					   ,URGRNM
				  FROM TADMIN_MST_URGR


					      #{SEARCH_CONDITION}





						ORDER BY #{colName} DESC


						ORDER BY #{colName} ASC



						ORDER BY URGRKEY ASC


#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

/* adm-role-rolebyusergroup-sql-oracle.xml - selectTAdminMstUrgrxrogt */
SELECT URGRKEY
	   ,ROKEY
  FROM TADMIN_MST_URGRXROGT



			URGRKEY = #{urgrkey}


			ROKEY = #{rokey}

mapper.insert:
/* adm-role-rolebyusergroup-sql-oracle.xml - insertTAdminMstUrgrxrogt */
INSERT INTO TADMIN_MST_URGRXROGT (
	 ROKEY
	 ,URGRKEY
	 ,INSERTURKEY
	 ,INSERTDATE
	 ,UPDATEURKEY
	 ,UPDATEDATE
) VALUES ( 
	 #{rokey}
	 ,#{urgrkey}
	 ,#{surkey}
	 ,#{sysdate}
	 ,#{surkey}
	 ,#{sysdate}

)

mapper.delete:
/* adm-role-rolebyusergroup-sql-oracle.xml - deleteTAdminMstUrgrxrogt */
DELETE 
  FROM TADMIN_MST_URGRXROGT
 WHERE ROKEY = #{rokey}
   AND URGRKEY = #{urgrkey}
